config_meson_libnvme() {
    CC="${CC}" "${MESON}" setup                 \
        --werror                                \
        --buildtype="${BUILDTYPE}"              \
        -Dnvme=disabled                         \
        -Dlibnvme=enabled                       \
        "${BUILDDIR}"
}

build_meson() {
    "${MESON}" compile                          \
        -C "${BUILDDIR}"
}

build_meson_docs() {
    "${MESON}" compile                          \
        -C "${BUILDDIR}"                        \
		docs
}

build_meson_man_docs() {
    "${MESON}" compile                          \
        -C "${BUILDDIR}"                        \
		docs
}

build_meson_html_docs() {
    "${MESON}" compile                          \
        -C "${BUILDDIR}"                        \
		docs
}

build_meson_rst_docs() {
    "${MESON}" compile                          \
        -C "${BUILDDIR}"                        \
		docs
}

test_meson() {
    local args=(-C "${BUILDDIR}")

    if [ "${use_valgrind:-0}" -eq 1 ]; then
        if command -v valgrind >/dev/null 2>&1; then
            args+=(--wrapper valgrind)
        else
            echo "Warning: valgrind requested but not found; running without it." >&2
        fi
    fi

    "${MESON}" test "${args[@]}"
